import 'antd/dist/reset.css'

import uniovi from './uniovi.png'
//import './App.css'; 
import { Routes, Route, Link, useNavigate } from 'react-router-dom';

import SearchComponent from './Components/SearchComponent';
import CreateUserComponent from './Components/CreateUserComponent';
import LoginUserComponent from './Components/LoginUserComponent';
import JournalsComponent from './Components/JournalsComponent';
import NewsComponent from './Components/NewsComponent';
import DashboardComponent from './Components/DashboardComponent'; 
import { Layout, Menu } from 'antd';
import { Header } from 'antd/es/layout/layout';
import { useEffect, useState } from 'react';




function App() {
  let [notification, setNotification] = useState("");
  let [login, setLogin] = useState(false)
  let navigate = useNavigate();

 


  return (

    <Layout className='la'>
      <Header>
              { !login && (
            <Menu theme="dark" mode="horizontal" items={[
                {key:"menuAbout", label:<Link to="/about">About</Link> },
                {key:"menuNews", label:<Link to="/news">News</Link> },
                {key:"Menusearch", label:<Link to="/search">Search</Link> },
               {key:"MenuJournals", label:<Link to="/journals">Journals</Link> },
             ]}>
            </Menu>
       )}

          { login && (
              <Menu theme="dark" items={[
               {key:"menuAbout", label:<Link to="/about">About</Link> },
               {key:"menuNews", label:<Link to="/news">News</Link> },
               {key:"Menusearch", label:<Link to="/search">Search</Link> },
               {key:"MenuJournals", label:<Link to="/journals">Journals</Link> },
              ]}>
             </Menu>
       )}
      </Header>
    
  
    

     
        <Routes>
            <Route path="/register" element={
              <CreateUserComponent/>
            }/>

            <Route path="/login" element={
              <LoginUserComponent/>
            }/>

            <Route path="/search" element={
              <SearchComponent/>
              
            }/>   

            <Route path="/journals" element={
              <JournalsComponent/>
              
            }/>   

            <Route path="/news" element={
              <NewsComponent/>
              
            }/>  
            <Route path="/dashboards" element={
              <DashboardComponent/>
              
            }/> 
      </Routes>
    </Layout>
      


  );
}

export default App;
